parameters.jsCode:
const payloads = items[0].json.data.document.historical_documents.payload;

const benefícios = payloads.map((beneficioArray, index) => {
  const beneficioObj = {};

  beneficioArray.forEach(campo => {
    beneficioObj[campo.title] = campo.value;
  });

  return {
    json: {
      beneficio_index: index + 1,
      ...beneficioObj
    }
  };
});

return benefícios;

